record_types.code:
type gsl_matrix is record
   size1 : aliased size_t;
   size2 : aliased size_t;
   tda   : aliased size_t;
   data  : access double;
   block : access gsl.block_double
     .gsl_block;
   owner : aliased int;
end record;

type u_gsl_matrix_const_view is record
   matrix : aliased gsl_matrix;
end record;

type u_gsl_matrix_view is record
   matrix : aliased gsl_matrix;
end record;

